import requests

BASE_URL = "http://localhost:5026"

def test_post_create_event_validation_error():
    url = f"{BASE_URL}/Event/Create"
    headers = {
        "Content-Type": "application/x-www-form-urlencoded"
    }
    # Missing required field "Title"
    payload = {
        "Img": "https://example.com/img.jpg",
        "Description": "Missing title",
        "Location": "Hall",
        "Status": "Active"
    }

    try:
        response = requests.post(url, data=payload, headers=headers, timeout=30)
    except requests.RequestException as e:
        assert False, f"Request failed: {e}"

    assert response.status_code == 200
    # Validation errors should be shown in the returned HTML view.
    content = response.text
    assert "validation" in content.lower() or "error" in content.lower() or "<span" in content.lower(), "Expected validation error indicators in response content"

test_post_create_event_validation_error()

import requests

def test_post_edit_event_not_found():
    base_url = "http://localhost:5026"
    non_existent_id = 9999
    url = f"{base_url}/Event/Edit/{non_existent_id}"
    payload = {
        "Id": non_existent_id,
        "Title": "NonExistent Event",
        "Img": "https://example.com/image.jpg",
        "Description": "This event does not exist",
        "Location": "Nowhere",
        "Status": "Active"
    }
    headers = {
        "Content-Type": "application/x-www-form-urlencoded"
    }
    try:
        response = requests.post(url, data=payload, headers=headers, timeout=30)
        assert response.status_code == 404, f"Expected 404 NotFound but got {response.status_code}"
    except requests.RequestException as e:
        assert False, f"Request failed: {e}"

test_post_edit_event_not_found()
